#include <stdio.h>
#include <stdlib.h>
#include <queue>
#define MAX_N 105
#define MAX_Q 105

int adj[MAX_N][MAX_N];
int dist[MAX_N][MAX_N];

void bfs(int start, int n) {
    std::queue<int> q;
    q.push(start);
    dist[start][start] = 0;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int v = 0; v < n; v++) {
            if (adj[u][v] == 1 && dist[start][v] == -1) {
                dist[start][v] = dist[start][u] + 1;
                q.push(v);
            }
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, Q;
        scanf("%d %d", &n, &Q);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                adj[i][j] = 0;
                dist[i][j] = -1;
            }
        }
        for (int i = 0; i < n - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--;
            v--;
            adj[u][v] = adj[v][u] = 1;
        }
        for (int i = 0; i < n; i++) {
            bfs(i, n);
        }
        for (int i = 0; i < Q; i++) {
            int x, y;
            scanf("%d %d", &x, &y);
            x--;
            y--;
            int ans = 0;
            while (x != y) {
                if (dist[x][y] == 1) {
                    ans++;
                    break;
                }
                if (dist[x][y] % 2 == 0) {
                    ans += dist[x][y] / 2;
                    break;
                } else {
                    ans += (dist[x][y] + 1) / 2;
                    break;
                }
            }
            printf("%d\n", ans);
        }
    }
    return 0;
}

